/**
 * Integration Module Types
 *
 * Type definitions for future integration module implementation.
 * This file defines interfaces for API management, webhooks,
 * and third-party service connections.
 *
 * @module modules/_stubs/integration/types
 *
 * @example
 * ```typescript
 * import type {
 *   IIntegrationService,
 *   Integration,
 *   Webhook,
 * } from '@/modules/_stubs/integration';
 * ```
 */

// -----------------------------------------------------------------------------
// Enums
// -----------------------------------------------------------------------------

/**
 * Integration status
 */
export enum IntegrationStatus {
  /** Integration is active */
  ACTIVE = 'ACTIVE',
  /** Integration is inactive */
  INACTIVE = 'INACTIVE',
  /** Integration has errors */
  ERROR = 'ERROR',
  /** Integration is pending setup */
  PENDING = 'PENDING',
}

/**
 * Integration type
 */
export enum IntegrationType {
  /** POS system */
  POS = 'POS',
  /** Payment gateway */
  PAYMENT = 'PAYMENT',
  /** Delivery service */
  DELIVERY = 'DELIVERY',
  /** Accounting software */
  ACCOUNTING = 'ACCOUNTING',
  /** CRM system */
  CRM = 'CRM',
  /** Marketing platform */
  MARKETING = 'MARKETING',
  /** Custom webhook */
  WEBHOOK = 'WEBHOOK',
  /** Custom API */
  CUSTOM = 'CUSTOM',
}

/**
 * Webhook event type
 */
export enum WebhookEvent {
  /** Order created */
  ORDER_CREATED = 'order.created',
  /** Order updated */
  ORDER_UPDATED = 'order.updated',
  /** Order completed */
  ORDER_COMPLETED = 'order.completed',
  /** Order cancelled */
  ORDER_CANCELLED = 'order.cancelled',
  /** Menu updated */
  MENU_UPDATED = 'menu.updated',
  /** Item updated */
  ITEM_UPDATED = 'item.updated',
  /** Customer created */
  CUSTOMER_CREATED = 'customer.created',
  /** Payment completed */
  PAYMENT_COMPLETED = 'payment.completed',
  /** Reservation created */
  RESERVATION_CREATED = 'reservation.created',
  /** Feedback submitted */
  FEEDBACK_SUBMITTED = 'feedback.submitted',
}

/**
 * Webhook delivery status
 */
export enum WebhookDeliveryStatus {
  /** Pending delivery */
  PENDING = 'PENDING',
  /** Successfully delivered */
  DELIVERED = 'DELIVERED',
  /** Delivery failed */
  FAILED = 'FAILED',
  /** Retrying delivery */
  RETRYING = 'RETRYING',
}

/**
 * API key status
 */
export enum ApiKeyStatus {
  /** Key is active */
  ACTIVE = 'ACTIVE',
  /** Key is revoked */
  REVOKED = 'REVOKED',
  /** Key is expired */
  EXPIRED = 'EXPIRED',
}

// -----------------------------------------------------------------------------
// Entity Types
// -----------------------------------------------------------------------------

/**
 * Integration entity
 */
export interface Integration {
  /** Integration ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Integration name */
  name: string;
  /** Integration type */
  type: IntegrationType;
  /** Provider (e.g., 'stripe', 'iyzico') */
  provider: string;
  /** Status */
  status: IntegrationStatus;
  /** Configuration (encrypted) */
  config: Record<string, unknown>;
  /** Credentials (encrypted) */
  credentials: Record<string, unknown>;
  /** Last sync timestamp */
  lastSyncAt: Date | null;
  /** Last error message */
  lastError: string | null;
  /** Created by user ID */
  createdById: string;
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

/**
 * Webhook entity
 */
export interface Webhook {
  /** Webhook ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Webhook name */
  name: string;
  /** Target URL */
  url: string;
  /** Events to trigger webhook */
  events: WebhookEvent[];
  /** Is active */
  isActive: boolean;
  /** Secret key for signature */
  secret: string;
  /** Custom headers */
  headers: Record<string, string> | null;
  /** Retry count */
  retryCount: number;
  /** Retry delay (seconds) */
  retryDelaySeconds: number;
  /** Total deliveries */
  totalDeliveries: number;
  /** Successful deliveries */
  successfulDeliveries: number;
  /** Failed deliveries */
  failedDeliveries: number;
  /** Last triggered at */
  lastTriggeredAt: Date | null;
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

/**
 * Webhook delivery
 */
export interface WebhookDelivery {
  /** Delivery ID */
  id: string;
  /** Webhook ID */
  webhookId: string;
  /** Event type */
  event: WebhookEvent;
  /** Payload sent */
  payload: Record<string, unknown>;
  /** Status */
  status: WebhookDeliveryStatus;
  /** HTTP status code */
  statusCode: number | null;
  /** Response body */
  response: string | null;
  /** Error message */
  error: string | null;
  /** Attempt count */
  attemptCount: number;
  /** Next retry at */
  nextRetryAt: Date | null;
  /** Duration (ms) */
  durationMs: number | null;
  /** Created at */
  createdAt: Date;
  /** Delivered at */
  deliveredAt: Date | null;
}

/**
 * API key entity
 */
export interface ApiKey {
  /** Key ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Key name */
  name: string;
  /** Key prefix (visible part) */
  keyPrefix: string;
  /** Key hash (for verification) */
  keyHash: string;
  /** Status */
  status: ApiKeyStatus;
  /** Scopes/permissions */
  scopes: string[];
  /** Rate limit (requests per minute) */
  rateLimit: number;
  /** Expires at */
  expiresAt: Date | null;
  /** Last used at */
  lastUsedAt: Date | null;
  /** Total requests */
  totalRequests: number;
  /** Created by user ID */
  createdById: string;
  /** Created at */
  createdAt: Date;
  /** Revoked at */
  revokedAt: Date | null;
}

// -----------------------------------------------------------------------------
// Request Types
// -----------------------------------------------------------------------------

/**
 * Create integration request
 */
export interface CreateIntegrationRequest {
  /** Integration name */
  name: string;
  /** Integration type */
  type: IntegrationType;
  /** Provider */
  provider: string;
  /** Configuration */
  config?: Record<string, unknown>;
  /** Credentials */
  credentials: Record<string, unknown>;
}

/**
 * Create webhook request
 */
export interface CreateWebhookRequest {
  /** Webhook name */
  name: string;
  /** Target URL */
  url: string;
  /** Events to subscribe */
  events: WebhookEvent[];
  /** Custom headers */
  headers?: Record<string, string>;
  /** Retry count (default: 3) */
  retryCount?: number;
  /** Retry delay in seconds (default: 60) */
  retryDelaySeconds?: number;
}

/**
 * Update webhook request
 */
export interface UpdateWebhookRequest {
  /** Webhook name */
  name?: string;
  /** Target URL */
  url?: string;
  /** Events to subscribe */
  events?: WebhookEvent[];
  /** Is active */
  isActive?: boolean;
  /** Custom headers */
  headers?: Record<string, string>;
  /** Retry count */
  retryCount?: number;
}

/**
 * Create API key request
 */
export interface CreateApiKeyRequest {
  /** Key name */
  name: string;
  /** Scopes/permissions */
  scopes: string[];
  /** Rate limit (default: 1000) */
  rateLimit?: number;
  /** Expires in days (optional) */
  expiresInDays?: number;
}

// -----------------------------------------------------------------------------
// Response Types
// -----------------------------------------------------------------------------

/**
 * Integration test result
 */
export interface IntegrationTestResult {
  /** Test passed */
  success: boolean;
  /** Response time (ms) */
  responseTimeMs: number;
  /** Error message */
  errorMessage?: string;
  /** Details */
  details?: Record<string, unknown>;
}

/**
 * API key creation result
 */
export interface ApiKeyCreationResult {
  /** Key ID */
  id: string;
  /** The actual API key (only shown once) */
  key: string;
  /** Key prefix */
  keyPrefix: string;
  /** Scopes */
  scopes: string[];
  /** Expires at */
  expiresAt: Date | null;
}

/**
 * Webhook stats
 */
export interface WebhookStats {
  /** Total deliveries */
  totalDeliveries: number;
  /** Successful deliveries */
  successfulDeliveries: number;
  /** Failed deliveries */
  failedDeliveries: number;
  /** Success rate percentage */
  successRate: number;
  /** Average response time (ms) */
  avgResponseTimeMs: number;
}

// -----------------------------------------------------------------------------
// Service Interfaces
// -----------------------------------------------------------------------------

/**
 * Integration service interface
 */
export interface IIntegrationService {
  /**
   * Create integration
   */
  createIntegration(
    organizationId: string,
    request: CreateIntegrationRequest
  ): Promise<Integration>;

  /**
   * Get integration by ID
   */
  getIntegration(
    organizationId: string,
    integrationId: string
  ): Promise<Integration>;

  /**
   * List integrations
   */
  listIntegrations(
    organizationId: string,
    type?: IntegrationType
  ): Promise<Integration[]>;

  /**
   * Update integration
   */
  updateIntegration(
    organizationId: string,
    integrationId: string,
    updates: Partial<CreateIntegrationRequest>
  ): Promise<Integration>;

  /**
   * Delete integration
   */
  deleteIntegration(
    organizationId: string,
    integrationId: string
  ): Promise<void>;

  /**
   * Test integration connection
   */
  testIntegration(
    organizationId: string,
    integrationId: string
  ): Promise<IntegrationTestResult>;

  /**
   * Sync integration data
   */
  syncIntegration(
    organizationId: string,
    integrationId: string
  ): Promise<void>;
}

/**
 * Webhook service interface
 */
export interface IWebhookService {
  /**
   * Create webhook
   */
  createWebhook(
    organizationId: string,
    request: CreateWebhookRequest
  ): Promise<Webhook>;

  /**
   * Get webhook by ID
   */
  getWebhook(
    organizationId: string,
    webhookId: string
  ): Promise<Webhook>;

  /**
   * List webhooks
   */
  listWebhooks(
    organizationId: string
  ): Promise<Webhook[]>;

  /**
   * Update webhook
   */
  updateWebhook(
    organizationId: string,
    webhookId: string,
    request: UpdateWebhookRequest
  ): Promise<Webhook>;

  /**
   * Delete webhook
   */
  deleteWebhook(
    organizationId: string,
    webhookId: string
  ): Promise<void>;

  /**
   * Get webhook deliveries
   */
  getDeliveries(
    organizationId: string,
    webhookId: string,
    limit?: number
  ): Promise<WebhookDelivery[]>;

  /**
   * Retry failed delivery
   */
  retryDelivery(
    organizationId: string,
    deliveryId: string
  ): Promise<WebhookDelivery>;

  /**
   * Get webhook stats
   */
  getStats(
    organizationId: string,
    webhookId: string
  ): Promise<WebhookStats>;

  /**
   * Test webhook
   */
  testWebhook(
    organizationId: string,
    webhookId: string
  ): Promise<WebhookDelivery>;
}

/**
 * API key service interface
 */
export interface IApiKeyService {
  /**
   * Create API key
   */
  createApiKey(
    organizationId: string,
    request: CreateApiKeyRequest
  ): Promise<ApiKeyCreationResult>;

  /**
   * List API keys
   */
  listApiKeys(
    organizationId: string
  ): Promise<ApiKey[]>;

  /**
   * Get API key by ID
   */
  getApiKey(
    organizationId: string,
    keyId: string
  ): Promise<ApiKey>;

  /**
   * Revoke API key
   */
  revokeApiKey(
    organizationId: string,
    keyId: string
  ): Promise<void>;

  /**
   * Validate API key
   */
  validateApiKey(
    key: string
  ): Promise<{ valid: boolean; organizationId?: string; scopes?: string[] }>;
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Integration connected event payload
 */
export interface IntegrationConnectedEventPayload {
  organizationId: string;
  integrationId: string;
  type: IntegrationType;
  provider: string;
  timestamp: string;
}

/**
 * Integration disconnected event payload
 */
export interface IntegrationDisconnectedEventPayload {
  organizationId: string;
  integrationId: string;
  reason: string;
  timestamp: string;
}

/**
 * Webhook triggered event payload
 */
export interface WebhookTriggeredEventPayload {
  organizationId: string;
  webhookId: string;
  deliveryId: string;
  event: WebhookEvent;
  status: WebhookDeliveryStatus;
  timestamp: string;
}

/**
 * API key created event payload
 */
export interface ApiKeyCreatedEventPayload {
  organizationId: string;
  keyId: string;
  keyPrefix: string;
  scopes: string[];
  createdById: string;
  timestamp: string;
}
